(function(){
'use strict';
document.documentElement.classList.add('js');
if(new URLSearchParams(location.search).get('demo')==='testimonials' && !location.pathname.includes('demo-testimonials')){ location.replace('/demo-testimonials.html'); return; }
var key='partyLanTheme', toggle=document.querySelector('.theme-toggle');
function apply(t,save){document.documentElement.dataset.theme=t;if(toggle){var d=t==='dark', label=d?'Switch to light mode':'Switch to dark mode', icon=d?'☀':'☾';toggle.setAttribute('aria-pressed',String(d));toggle.setAttribute('aria-label',label);toggle.setAttribute('title',label);var i=toggle.querySelector('.theme-toggle__icon'); if(i)i.textContent=icon;} if(save)try{localStorage.setItem(key,t)}catch(e){}}
apply(document.documentElement.dataset.theme||'light',false); if(toggle)toggle.addEventListener('click',function(){apply(document.documentElement.dataset.theme==='dark'?'light':'dark',true)});
var mt=document.querySelector('.menu-toggle'), menu=document.getElementById('site-menu'); if(mt&&menu){mt.addEventListener('click',function(){var o=menu.classList.toggle('is-open');mt.setAttribute('aria-expanded',String(o));}); menu.addEventListener('click',function(e){if(e.target.tagName==='A'){menu.classList.remove('is-open');mt.setAttribute('aria-expanded','false')}})}
document.querySelectorAll('.package-expand').forEach(function(b){b.addEventListener('click',function(){var c=b.closest('.package-card'), open=c.classList.toggle('is-expanded'); b.setAttribute('aria-expanded',String(open));});});
document.querySelectorAll('.faq-item button').forEach(function(b){b.addEventListener('click',function(){document.querySelectorAll('.faq-item button').forEach(function(x){if(x!==b){x.setAttribute('aria-expanded','false');x.closest('.faq-item').classList.remove('is-open')}});var open=b.getAttribute('aria-expanded')!=='true';b.setAttribute('aria-expanded',String(open));b.closest('.faq-item').classList.toggle('is-open',open);});});
function makeSlider(root, slideSelector, dotBoxSelector, labelFn, interval){var all=[].slice.call(root.querySelectorAll(slideSelector)), dotBox=root.querySelector(dotBoxSelector), slides=all, idx=0, timer, reduced=matchMedia('(prefers-reduced-motion: reduce)').matches, sx=0, sy=0, dragging=false, paused=reduced, toggle=root.querySelector('.showcase-toggle'), feedback=root.querySelector('.showcase-feedback'); function updateToggle(){if(toggle){var noun=root.classList.contains('testimonial-stage')?'testimonials':'gallery';toggle.setAttribute('aria-pressed',String(paused));toggle.setAttribute('aria-label',paused?'Play '+noun:'Pause '+noun);toggle.querySelector('span').textContent=paused?'▶':'Ⅱ';}} function pulse(icon){if(feedback){feedback.textContent=icon;feedback.classList.add('is-visible');setTimeout(function(){feedback.classList.remove('is-visible')},520);}} function renderDots(){if(!dotBox)return; dotBox.innerHTML=''; slides.forEach(function(_,i){var b=document.createElement('button');b.type='button';b.className='slider-dot';b.setAttribute('aria-label',labelFn(i));b.innerHTML='<span></span>';b.addEventListener('click',function(){paused=true;go(i,true);updateToggle();});dotBox.appendChild(b);});} function go(n,manual){if(!slides.length)return;idx=(n+slides.length)%slides.length;all.forEach(function(s){s.classList.remove('is-active');s.setAttribute('aria-hidden','true')});slides[idx].classList.add('is-active');slides[idx].setAttribute('aria-hidden','false');[].slice.call(dotBox?dotBox.children:[]).forEach(function(d,i){d.setAttribute('aria-current',String(i===idx))}); if(manual)stop();} function stop(){clearInterval(timer);timer=null;} function start(){stop(); if(!paused&&!reduced&&slides.length>1)timer=setInterval(function(){go(idx+1,false)},interval||8500);} function togglePaused(){paused=!paused;updateToggle();pulse(paused?'Ⅱ':'▶');start();} root.addEventListener('mouseenter',function(){stop();});root.addEventListener('focusin',function(){stop();});root.addEventListener('mouseleave',start);root.addEventListener('touchstart',function(e){sx=e.touches[0].clientX;sy=e.touches[0].clientY},{passive:true});root.addEventListener('touchend',function(e){var dx=e.changedTouches[0].clientX-sx;if(Math.abs(dx)>40){paused=true;go(idx+(dx<0?1:-1),true);updateToggle();}},{passive:true});root.addEventListener('pointerdown',function(e){if(e.target.closest('button'))return;dragging=true;sx=e.clientX;sy=e.clientY;root.setPointerCapture&&root.setPointerCapture(e.pointerId)});root.addEventListener('pointerup',function(e){if(!dragging)return;dragging=false;var dx=e.clientX-sx,dy=e.clientY-sy;if(Math.abs(dx)>50){paused=true;go(idx+(dx<0?1:-1),true);updateToggle();}else if(Math.abs(dx)<8&&Math.abs(dy)<8&&root.classList.contains('showcase')){togglePaused();}}); if(toggle){toggle.addEventListener('click',togglePaused);} updateToggle();return{setSlides:function(next){slides=next;idx=0;renderDots();go(0,false);start();},go:go,stop:stop,start:start,isPaused:function(){return paused;}};}
document.querySelectorAll('.testimonial-stage').forEach(function(stage){var slider=makeSlider(stage,'.testimonial-slide','.testimonial-dots',function(i){return 'Show testimonial '+(i+1);},8000);slider.setSlides([].slice.call(stage.querySelectorAll('.testimonial-slide')));});
document.querySelectorAll('.showcase').forEach(function(showcase){var section=showcase.closest('.showcase-section'), tabs=[].slice.call(section.querySelectorAll('[data-gallery-tab]')), all=[].slice.call(showcase.querySelectorAll('.showcase-slide')), activeCat='experience', slider=makeSlider(showcase,'.showcase-slide','.showcase-indicators',function(i){return 'Show '+activeCat+' image '+(i+1);},9000); function select(cat){activeCat=cat;tabs.forEach(function(t){t.setAttribute('aria-selected',String(t.dataset.galleryTab===cat))});slider.setSlides(all.filter(function(s){return s.dataset.category===cat}));} tabs.forEach(function(t,i){t.addEventListener('click',function(){select(t.dataset.galleryTab)});t.addEventListener('keydown',function(e){if(e.key==='ArrowRight'||e.key==='ArrowLeft'){e.preventDefault();var n=(i+(e.key==='ArrowRight'?1:-1)+tabs.length)%tabs.length;tabs[n].focus();tabs[n].click();}})});select(activeCat);});
var io=('IntersectionObserver'in window&&!matchMedia('(prefers-reduced-motion: reduce)').matches)?new IntersectionObserver(function(es){es.forEach(function(e){if(e.isIntersecting){e.target.classList.add('is-visible');io.unobserve(e.target)}})},{threshold:.12}):null;document.querySelectorAll('.reveal').forEach(function(el){io?io.observe(el):el.classList.add('is-visible')});
}());
